const XLSX = require\('xlsx'\);
const wb = XLSX.readFile\('Planilha de gasto-v.2024 1 \(1\).xlsx'\);

const MONTH_SHEET = /^\(Jan|Fev|Mar|Abr|Mai|Jun|Jul|Ago|Set|Out|Nov|Dez\)\\d{2}$/;
const monthSheets = wb.SheetNames.filter\(n => MONTH_SHEET.test\(n\)\);
console.log\('Primeira aba de mês:', monthSheets[0]\);
console.log\('Últimas 5 abas:', monthSheets.slice\(-5\)\);

// Para cada aba, capturar: saldo inicial \(linha com SALDO sem transação\) e todos os DINHEIRO
function analyzeSheet\(sheetName\) {
  const ws = wb.Sheets[sheetName];
  const rows = XLSX.utils.sheet_to_json\(ws, { header: 1, defval: '' }\);

  let headerIdx = -1;
  for \(let i = 0; i < rows.length; i++\) {
    if \(rows[i].includes\('CATEGORIA'\)\) { headerIdx = i; break; }
  }
  if \(headerIdx < 0\) return null;

  // Saldo inicial = primeira ocorrência de SALDO \(col 35\) em linha sem data/método
  let saldoInicial = null;
  let saldoFinal = null;
  let dinheiroRows = [];

  for \(let i = headerIdx + 1; i < rows.length; i++\) {
    const r = rows[i];
    const saldo = r[35];
    const method = String\(r[19] || ''\).trim\(\).toUpperCase\(\);
    const value = parseFloat\(r[20]\);
    const day = r[1];

    if \(saldo !== '' && !isNaN\(parseFloat\(saldo\)\) && parseFloat\(saldo\) !== 0\) {
      if \(saldoInicial === null\) saldoInicial = parseFloat\(saldo\);
      saldoFinal = parseFloat\(saldo\);
    }

    if \(method === 'DINHEIRO' && !isNaN\(value\) && value !== 0\) {
      dinheiroRows.push\({ day, value }\);
    }
  }

  return { sheetName, saldoInicial, saldoFinal, 
           dinheiroSum: dinheiroRows.reduce\(\(a, r\) => a + r.value, 0\),
           dinheiroCount: dinheiroRows.length };
}

// Analisar todas as abas
const results = monthSheets.map\(analyzeSheet\).filter\(Boolean\);

// Mostrar as últimas 12 e as primeiras 3
console.log\('\\nPrimeiras abas:'\);
results.slice\(0, 3\).forEach\(r => console.log\(r\)\);
console.log\('\\nÚltimas 12 abas:'\);
results.slice\(-12\).forEach\(r => console.log\(r\)\);
